const items = $input.all();

for (const item of items) {
  const body = item.json.body || {};

  // Normalizar supervisorEmails
  const supervisorEmails = (body.supervisorEmails || '')
    .split(',')
    .map(e => e.trim())
    .filter(Boolean)
    .join(',');

  item.json.supervisorEmails = supervisorEmails;
  item.json.hasSupervisorEmails = supervisorEmails.length > 0;

  // Campos útiles en raíz
  item.json.reportId = body.reportId || '';
  item.json.employeeId = body.employeeId || '';
  item.json.employeeName = body.employeeName || '';
  item.json.targetEmails = body.targetEmails || '';
  item.json.employeeEmail = body.employeeEmail || '';
  item.json.reportTitle = body.reportTitle || '';

  // Comercio / Empresa (fallbacks)
  item.json.comercio = body.comercio || body.merchant || body.merchantName || '';
  item.json.empresa = body.empresa || body.company || '';
  item.json.comercioOEmpresa = item.json.comercio || item.json.empresa || 'No informado';

  // Adjunto Excel
  if (body.excelBase64) {
    const cleanBase64 = String(body.excelBase64).includes(',')
      ? String(body.excelBase64).split(',')[1]
      : String(body.excelBase64);

    item.binary = item.binary || {};
    item.binary.adjunto_excel = {
      data: cleanBase64,
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: body.excelName || 'Rendicion.xlsx'
    };
  }
}

return items;

