// FORZAMOS la lectura desde el nodo inicial "Webhook"
const webhookData = $('Webhook').item.json.body; 
let odoo_uid = $('HTTP Request').item.json.result;

const monedaOdoo = {
  "UYU": 45, "ARS": 18, "USD": 1, "MXN": 32, "CLP": 44
};

const sociedades = {
  "Uruguay": { company_id: 15, account_debe: 3013, account_haber: 12790 },
  "Argentina": { company_id: 11, account_debe: 5942, account_haber: 12789 },
  "Chile": { company_id: 14, account_debe: 2143, account_haber: 12784 },
  "Mexico": { company_id: 3, account_debe: 2577, account_haber: 12785 },
  "Regional": { company_id: 1, account_debe: 2577, account_haber: 12785 }
};

const paisCliente = (webhookData.country || "").trim();
const paisKey = Object.keys(sociedades).find(k => k.toLowerCase() === paisCliente.toLowerCase());
const config = sociedades[paisKey] || sociedades[paisCliente.replace('é','e')] || sociedades["Uruguay"];

const budgetCurrency = webhookData.budgetCurrency || "UYU";
const odooCurrencyId = monedaOdoo[budgetCurrency] || 45;
const rates = webhookData.exchangeRates || {};

// 1. CÁLCULO DE MONTOS
let finalAmount = 0; // Valor en la moneda del reporte (MXN, UYU, etc.)
let totalUSD = 0;    // Valor convertido a USD (Moneda base de tus sociedades en Odoo)

if (webhookData.expenseDetails && webhookData.expenseDetails.length > 0) {
    webhookData.expenseDetails.forEach(exp => {
        let expAmount = parseFloat(exp.amount) || 0;
        let expCur = exp.currency || "UYU";
        let rateToUsd = rates[expCur] || 1;

        let expInUSD = expCur === "USD" ? expAmount : (expAmount / rateToUsd);
        totalUSD += expInUSD;

        if (expCur === budgetCurrency) {
            finalAmount += expAmount;
        } else {
            let rateFromUsdToBudget = rates[budgetCurrency] || 1;
            finalAmount += (expCur === "USD") ? (expAmount * rateFromUsdToBudget) : (expInUSD * rateFromUsdToBudget);
        }
    });
}

finalAmount = Math.round(finalAmount * 100) / 100;
totalUSD = Math.round(totalUSD * 100) / 100;

const ref = `Rendición: ${webhookData.reportTitle || 'Sin Título'} - ${webhookData.employeeName || 'Empleado'}`;

// 2. CREACIÓN DE LÍNEAS - CORRECCIÓN DE DEBIT/CREDIT
// IMPORTANTE: 'debit' y 'credit' siempre van en la moneda de la compañía (USD para cids=3)
const line_ids = [
  [0, 0, {
    "name": ref,
    "account_id": config.account_debe,
    "currency_id": odooCurrencyId,
    "amount_currency": finalAmount, // El valor nominal en MXN
    "debit": totalUSD,              // EL CAMBIO: Ahora mandamos los 6.70 USD aquí
    "credit": 0,
    "debit_usd": totalUSD,
    "credit_usd": 0
  }],
  [0, 0, {
    "name": ref,
    "account_id": config.account_haber,
    "currency_id": odooCurrencyId,
    "amount_currency": -finalAmount, // El valor nominal en MXN negativo
    "debit": 0,
    "credit": totalUSD,              // EL CAMBIO: Ahora mandamos los 6.70 USD aquí
    "debit_usd": 0,
    "credit_usd": totalUSD
  }]
];

return {
  json: {
    jsonrpc: "2.0",
    method: "call",
    params: {
      service: "object",
      method: "execute_kw",
      args: [
        "zanello1234-southgeneticsv17-main-10564043",
        odoo_uid,
        "c6693a825154ecac81bed79b2725dbc95ffb8008",
        "account.move",
        "create",
        [{
          date: new Date().toISOString().split('T')[0],
          company_id: config.company_id,
          move_type: "entry",
          ref: ref,
          line_ids: line_ids
        }]
      ]
    },
    id: 1
  }
};

