const item = $input.first().json;
let raw = '';
if (item.content && item.content.parts && item.content.parts[0]) raw = item.content.parts[0].text;
else if (item.text) raw = item.text;
raw = raw.replace(/\x60\x60\x60json[\n\r]?/gi,'').replace(/\x60\x60\x60/g,'').trim();
let parsed;
try { parsed = JSON.parse(raw); } catch(e) { parsed = {monto:null,fecha:null,merchant_name:null}; }
if (parsed.monto === 0) parsed.monto = null;
const hasData = parsed.monto !== null || parsed.fecha !== null || parsed.merchant_name !== null;
return [{ json: { ...parsed, _hasData: hasData } }];

